export default function Terms() {
  return (
    <div style={{ maxWidth: 720, margin: "0 auto", padding: "40px 20px" }}>
      <h1 style={{ fontFamily: "'Josefin Sans',sans-serif", fontSize: 22, marginBottom: 16 }}>Conditions générales de vente</h1>
      <p style={{ color: "#555", lineHeight: 1.8, marginBottom: 12 }}>
        Les commandes sont payées en espèces à la livraison (COD). Les délais indicatifs sont de 24 h pour Alger et 48–72 h pour les autres wilayas, sous réserve de disponibilité du transporteur.
      </p>
      <p style={{ color: "#555", lineHeight: 1.8 }}>Les retours sont acceptés conformément à notre politique affichée en boutique et sur demande par email.</p>
    </div>
  );
}
